export interface FlashcardData {
  front: string;
  back: string;
}

export interface GeneratedContent {
  markdownNotes: string;
  flashcards: FlashcardData[];
}

export interface UploadedFile {
  id: string;
  data: string; // Base64
  mimeType: string;
}

export enum ViewMode {
  INPUT = 'INPUT',
  NOTES = 'NOTES',
  FLASHCARDS = 'FLASHCARDS'
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { GeneratedContent, UploadedFile } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    markdownNotes: {
      type: Type.STRING,
      description: "Comprehensive study notes in Markdown format based on the input material. Use headings, bullet points, and bold text for clarity.",
    },
    flashcards: {
      type: Type.ARRAY,
      description: "A list of flashcards generated from the key concepts.",
      items: {
        type: Type.OBJECT,
        properties: {
          front: {
            type: Type.STRING,
            description: "The question or concept on the front of the card.",
          },
          back: {
            type: Type.STRING,
            description: "The answer or definition on the back of the card.",
          },
        },
        required: ["front", "back"],
      },
    },
  },
  required: ["markdownNotes", "flashcards"],
};

export const generateStudyMaterial = async (
  text: string,
  files: UploadedFile[]
): Promise<GeneratedContent> => {
  try {
    const parts: any[] = [];

    // Generic prompt that handles both scenarios (Screen Capture OR Manual Upload)
    const promptText = `
      You are an expert study companion. 
      The user has provided course materials to study. This input may consist of:
      1. A chronological series of screen captures from a video/reading session.
      2. A PDF document (e.g., textbook chapter, lecture slides).
      3. A set of static diagrams or images.
      4. Raw text notes pasted by the user.

      Your task:
      1. Analyze the provided content thoroughly. 
      2. Identify the core topics, definitions, and key concepts.
      3. Create comprehensive study notes in Markdown. Organize them logically with headers, even if the input was unstructured.
      4. Generate high-quality flashcards to test understanding of these specific concepts.

      Note for Screen Captures: If the images look like a video timeline, treat them chronologically and ignore duplicates.
    `;

    parts.push({ text: promptText });

    if (text.trim()) {
      parts.push({ text: `User Provided Text/Context:\n${text}` });
    }

    // Add file parts (Images or PDFs)
    files.forEach((file) => {
      // Remove data url prefix if present (e.g., "data:image/png;base64,")
      // The API expects just the base64 string.
      const base64Data = file.data.includes(',') ? file.data.split(',')[1] : file.data;

      parts.push({
        inlineData: {
          mimeType: file.mimeType,
          data: base64Data,
        },
      });
    });

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        systemInstruction: "You are a helpful, accurate, and educational AI assistant.",
      },
    });

    if (!response.text) {
      throw new Error("No response generated from Gemini.");
    }

    const data = JSON.parse(response.text) as GeneratedContent;
    return data;
  } catch (error) {
    console.error("Error generating study material:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { FlashcardData } from '../types';
import { ChevronLeft, ChevronRight, RefreshCw, Layers, Download } from 'lucide-react';

interface FlashcardDeckProps {
  cards: FlashcardData[];
}

const FlashcardDeck: React.FC<FlashcardDeckProps> = ({ cards }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  if (!cards || cards.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-slate-400">
        <Layers className="w-12 h-12 mb-2" />
        <p>No flashcards generated yet.</p>
      </div>
    );
  }

  const handleNext = () => {
    setIsFlipped(false);
    setTimeout(() => {
      setCurrentIndex((prev) => (prev + 1) % cards.length);
    }, 200);
  };

  const handlePrev = () => {
    setIsFlipped(false);
    setTimeout(() => {
      setCurrentIndex((prev) => (prev - 1 + cards.length) % cards.length);
    }, 200);
  };

  const handleFlip = () => {
    setIsFlipped(!isFlipped);
  };

  const exportToAnki = () => {
    // Escape quotes by doubling them, and wrap fields in quotes
    const csvContent = cards.map(card => {
        const front = `"${card.front.replace(/"/g, '""')}"`;
        const back = `"${card.back.replace(/"/g, '""')}"`;
        return `${front},${back}`;
    }).join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', 'study_flashcards.csv');
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const currentCard = cards[currentIndex];

  return (
    <div className="flex flex-col items-center w-full max-w-2xl mx-auto p-4">
      <div className="w-full flex justify-between items-center mb-4">
        <span className="text-slate-600 font-medium">Card {currentIndex + 1} of {cards.length}</span>

        <div className="flex gap-4">
            <button 
                onClick={exportToAnki}
                className="text-slate-600 hover:text-indigo-600 text-sm flex items-center gap-1 transition-colors"
                title="Download CSV for Anki"
            >
                <Download size={14} /> Export CSV
            </button>
            <button 
                onClick={() => { setIsFlipped(false); setCurrentIndex(0); }}
                className="text-slate-600 hover:text-indigo-600 text-sm flex items-center gap-1 transition-colors"
            >
                <RefreshCw size={14} /> Restart
            </button>
        </div>
      </div>

      <div 
        className="relative w-full h-80 sm:h-96 perspective-1000 cursor-pointer group"
        onClick={handleFlip}
      >
        <div 
          className={`absolute w-full h-full transition-all duration-500 transform-style-3d shadow-xl rounded-2xl ${isFlipped ? 'rotate-y-180' : ''}`}
        >
          {/* Front */}
          <div className="absolute w-full h-full bg-white border border-slate-200 rounded-2xl p-8 flex flex-col items-center justify-center text-center backface-hidden">
            <h3 className="text-sm uppercase tracking-wider text-indigo-500 font-bold mb-4">Question</h3>
            <p className="text-xl sm:text-2xl font-medium text-slate-800 overflow-y-auto max-h-full">
              {currentCard.front}
            </p>
            <p className="absolute bottom-4 text-xs text-slate-400">Click to flip</p>
          </div>

          {/* Back */}
          <div className="absolute w-full h-full bg-indigo-50 border border-indigo-100 rounded-2xl p-8 flex flex-col items-center justify-center text-center backface-hidden rotate-y-180">
            <h3 className="text-sm uppercase tracking-wider text-indigo-500 font-bold mb-4">Answer</h3>
            <p className="text-lg sm:text-xl text-slate-700 overflow-y-auto max-h-full">
              {currentCard.back}
            </p>
            <p className="absolute bottom-4 text-xs text-indigo-300">Click to flip back</p>
          </div>
        </div>
      </div>

      <div className="flex gap-4 mt-8">
        <button 
          onClick={handlePrev}
          className="p-3 rounded-full bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 hover:border-slate-300 transition-colors shadow-sm disabled:opacity-50"
          disabled={cards.length <= 1}
        >
          <ChevronLeft size={24} />
        </button>
        <button 
          onClick={handleFlip}
          className="px-6 py-2 bg-indigo-600 text-white rounded-full font-medium shadow-md hover:bg-indigo-700 transition-colors"
        >
            {isFlipped ? 'Show Question' : 'Show Answer'}
        </button>
        <button 
          onClick={handleNext}
          className="p-3 rounded-full bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 hover:border-slate-300 transition-colors shadow-sm disabled:opacity-50"
          disabled={cards.length <= 1}
        >
          <ChevronRight size={24} />
        </button>
      </div>
    </div>
  );
};

export default FlashcardDeck;

import React, { useState, useRef, useEffect } from 'react';
import { UploadedFile } from '../types';
import { Monitor, StopCircle, Play, X, Trash2, Camera, Film, Upload, FileText, File as FileIcon } from 'lucide-react';

interface InputSectionProps {
  onGenerate: (text: string, files: UploadedFile[]) => void;
  isGenerating: boolean;
}

type InputMode = 'screen' | 'upload';

const InputSection: React.FC<InputSectionProps> = ({ onGenerate, isGenerating }) => {
  const [mode, setMode] = useState<InputMode>('screen');

  // Screen Capture State
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImages, setCapturedImages] = useState<UploadedFile[]>([]);
  const [isRecording, setIsRecording] = useState(false);

  // Manual Upload State
  const [manualText, setManualText] = useState("");
  const [uploadedFiles, setUploadedFiles] = useState<UploadedFile[]>([]);

  // Refs for Capture
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const lastFrameDataRef = useRef<string | null>(null);
  const intervalRef = useRef<number | null>(null);

  // Cleanup stream on unmount
  useEffect(() => {
    return () => {
      stopCapture();
    };
  }, []);

  // Attach stream to video element when available
  useEffect(() => {
    if (videoRef.current && stream) {
      videoRef.current.srcObject = stream;
    }
  }, [stream]);

  // --- Screen Capture Logic ---

  const startCapture = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getDisplayMedia({
        video: {
          cursor: "always"
        } as any,
        audio: false
      });

      setStream(mediaStream);
      setIsRecording(true);

      mediaStream.getVideoTracks()[0].onended = () => {
        stopCapture();
      };

      intervalRef.current = window.setInterval(checkForChanges, 2000); 
    } catch (err) {
      console.error("Error starting screen capture:", err);
    }
  };

  const stopCapture = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    setIsRecording(false);
  };

  const captureFrame = () => {
    if (!videoRef.current || !canvasRef.current) return;

    const video = videoRef.current;
    const canvas = canvasRef.current;
    const context = canvas.getContext('2d');
    if (!context) return;

    const scale = Math.min(1, 1280 / video.videoWidth);
    canvas.width = video.videoWidth * scale;
    canvas.height = video.videoHeight * scale;

    context.drawImage(video, 0, 0, canvas.width, canvas.height);

    const base64String = canvas.toDataURL('image/jpeg', 0.8);

    const newImage: UploadedFile = {
      id: Date.now().toString(),
      data: base64String,
      mimeType: 'image/jpeg'
    };

    setCapturedImages(prev => [...prev, newImage]);
    return base64String;
  };

  const checkForChanges = () => {
    if (!videoRef.current || !canvasRef.current) return;

    const diffCanvas = document.createElement('canvas');
    diffCanvas.width = 64; 
    diffCanvas.height = 64;
    const ctx = diffCanvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(videoRef.current, 0, 0, 64, 64);
    const lowResData = diffCanvas.toDataURL();

    if (lastFrameDataRef.current !== lowResData) {
      captureFrame();
      lastFrameDataRef.current = lowResData;
    }
  };

  // --- Manual Upload Logic ---

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      Array.from(e.target.files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          const base64String = reader.result as string;
          setUploadedFiles(prev => [...prev, {
            id: Date.now().toString() + Math.random(),
            data: base64String,
            mimeType: file.type
          }]);
        };
        reader.readAsDataURL(file);
      });
    }
  };

  // --- Common Logic ---

  const removeFile = (id: string, isCapture: boolean) => {
    if (isCapture) {
      setCapturedImages(prev => prev.filter(f => f.id !== id));
    } else {
      setUploadedFiles(prev => prev.filter(f => f.id !== id));
    }
  };

  const handleGenerateClick = () => {
    stopCapture();
    if (mode === 'screen') {
      onGenerate("", capturedImages);
    } else {
      onGenerate(manualText, uploadedFiles);
    }
  };

  const isGenerateDisabled = () => {
    if (isGenerating) return true;
    if (mode === 'screen') return capturedImages.length === 0;
    if (mode === 'upload') return manualText.trim().length === 0 && uploadedFiles.length === 0;
    return true;
  };

  const switchMode = (newMode: InputMode) => {
    if (isRecording) stopCapture();
    setMode(newMode);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">

      {/* Mode Tabs */}
      <div className="flex p-1 bg-slate-200 rounded-xl w-fit mx-auto mb-6">
        <button
          onClick={() => switchMode('screen')}
          className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-medium transition-all ${
            mode === 'screen' 
              ? 'bg-white text-indigo-600 shadow-sm' 
              : 'text-slate-600 hover:text-slate-800'
          }`}
        >
          <Monitor size={16} /> Live Capture
        </button>
        <button
          onClick={() => switchMode('upload')}
          className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-medium transition-all ${
            mode === 'upload' 
              ? 'bg-white text-indigo-600 shadow-sm' 
              : 'text-slate-600 hover:text-slate-800'
          }`}
        >
          <Upload size={16} /> Upload & Paste
        </button>
      </div>

      <canvas ref={canvasRef} className="hidden" />

      {/* === SCREEN CAPTURE UI === */}
      {mode === 'screen' && (
        <>
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-slate-50">
              <div className="flex items-center gap-2">
                <Monitor className="text-indigo-600" size={20} />
                <h2 className="font-semibold text-slate-700">Screen Reader</h2>
              </div>
              {isRecording && (
                <div className="flex items-center gap-2 px-3 py-1 bg-red-100 text-red-600 rounded-full text-xs font-medium animate-pulse">
                    <div className="w-2 h-2 bg-red-500 rounded-full" />
                    Recording Source
                </div>
              )}
            </div>

            <div className="relative bg-slate-900 aspect-video flex items-center justify-center overflow-hidden group">
              {stream ? (
                <video 
                  ref={videoRef} 
                  autoPlay 
                  muted 
                  className="w-full h-full object-contain"
                />
              ) : (
                <div className="text-center p-8">
                  <div className="w-16 h-16 bg-slate-800 rounded-2xl flex items-center justify-center mx-auto mb-4">
                    <Monitor className="text-slate-500" size={32} />
                  </div>
                  <h3 className="text-slate-200 font-medium mb-2">Share your course material</h3>
                  <p className="text-slate-400 text-sm max-w-md mx-auto mb-6">
                    We'll monitor your screen and automatically capture slides, pages, or notes as you read through them.
                  </p>
                  <button
                    onClick={startCapture}
                    className="inline-flex items-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-medium transition-all shadow-lg hover:shadow-indigo-500/25"
                  >
                    <Play size={18} fill="currentColor" />
                    Start Study Session
                  </button>
                </div>
              )}

              {isRecording && (
                <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-4">
                  <button
                    onClick={captureFrame}
                    className="flex items-center gap-2 px-4 py-2 bg-white/10 hover:bg-white/20 backdrop-blur-md text-white rounded-lg text-sm font-medium transition-colors border border-white/10"
                  >
                    <Camera size={16} />
                    Snap Now
                  </button>
                  <button
                    onClick={stopCapture}
                    className="flex items-center gap-2 px-4 py-2 bg-red-500/80 hover:bg-red-600/90 backdrop-blur-md text-white rounded-lg text-sm font-medium transition-colors shadow-lg"
                  >
                    <StopCircle size={16} />
                    Stop Recording
                  </button>
                </div>
              )}
            </div>
          </div>

          {/* Timeline for Screen Mode */}
          {(capturedImages.length > 0 || isRecording) && (
            <div className="bg-white rounded-xl border border-slate-200 p-4 shadow-sm animate-in fade-in slide-in-from-bottom-4">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-sm font-semibold text-slate-700 flex items-center gap-2">
                  <Film size={16} className="text-slate-400" />
                  Captured Timeline <span className="text-xs bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-full">{capturedImages.length} frames</span>
                </h3>
                {capturedImages.length > 0 && (
                    <button 
                        onClick={() => setCapturedImages([])}
                        className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1"
                    >
                        <Trash2 size={12} /> Clear all
                    </button>
                )}
              </div>

              {capturedImages.length === 0 ? (
                <div className="h-32 border-2 border-dashed border-slate-200 rounded-lg flex flex-col items-center justify-center text-slate-400 text-sm bg-slate-50/50">
                    <p>Waiting for content...</p>
                    <p className="text-xs opacity-70 mt-1">Navigate through your material to auto-capture</p>
                </div>
              ) : (
                <div className="flex gap-4 overflow-x-auto pb-4 pt-1 px-1 snap-x">
                    {capturedImages.map((img, index) => (
                    <div key={img.id} className="relative flex-shrink-0 w-48 aspect-video group snap-center">
                        <img 
                          src={img.data} 
                          alt={`Capture ${index + 1}`} 
                          className="w-full h-full object-cover rounded-lg border border-slate-200 shadow-sm"
                        />
                        <div className="absolute top-1 right-1 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button
                                onClick={() => removeFile(img.id, true)}
                                className="bg-black/50 hover:bg-black/70 text-white p-1 rounded-full backdrop-blur-sm"
                            >
                                <X size={12} />
                            </button>
                        </div>
                        <div className="absolute bottom-1 right-1 bg-black/50 backdrop-blur-sm text-white text-[10px] px-1.5 py-0.5 rounded">
                            #{index + 1}
                        </div>
                    </div>
                    ))}
                </div>
              )}
            </div>
          )}
        </>
      )}

      {/* === MANUAL UPLOAD UI === */}
      {mode === 'upload' && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Text Input */}
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 flex flex-col h-[400px]">
             <div className="flex items-center gap-2 mb-3 text-slate-700 font-medium">
               <FileText size={18} />
               <h3>Paste Text Notes</h3>
             </div>
             <textarea 
               className="flex-1 w-full bg-slate-50 border border-slate-200 rounded-xl p-4 resize-none focus:outline-none focus:ring-2 focus:ring-indigo-500/50"
               placeholder="Paste lecture notes, articles, or summaries here..."
               value={manualText}
               onChange={(e) => setManualText(e.target.value)}
             />
          </div>

          {/* File Upload */}
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 flex flex-col h-[400px]">
             <div className="flex items-center gap-2 mb-3 text-slate-700 font-medium">
               <Upload size={18} />
               <h3>Upload Files (PDF/Images)</h3>
             </div>

             <div className="flex-1 relative border-2 border-dashed border-slate-200 rounded-xl bg-slate-50 hover:bg-slate-100 transition-colors flex flex-col items-center justify-center text-center p-6 group">
                <input 
                  type="file" 
                  multiple 
                  accept="image/*,application/pdf"
                  onChange={handleFileUpload}
                  className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                />
                <div className="w-12 h-12 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mb-3 group-hover:scale-110 transition-transform">
                  <Upload size={24} />
                </div>
                <p className="text-slate-700 font-medium">Click to upload or drag & drop</p>
                <p className="text-xs text-slate-500 mt-1">PDF documents, Screenshots, Diagrams</p>
             </div>

             {/* File List */}
             {uploadedFiles.length > 0 && (
               <div className="mt-4 h-32 overflow-y-auto pr-2 space-y-2">
                 {uploadedFiles.map((file) => (
                   <div key={file.id} className="flex items-center justify-between bg-slate-50 border border-slate-200 p-2 rounded-lg">
                      <div className="flex items-center gap-2 overflow-hidden">
                        {file.mimeType.includes('image') ? (
                          <img src={file.data} alt="thumb" className="w-8 h-8 rounded object-cover bg-white" />
                        ) : (
                          <div className="w-8 h-8 rounded bg-red-100 text-red-600 flex items-center justify-center flex-shrink-0">
                            <FileIcon size={14} />
                          </div>
                        )}
                        <span className="text-xs text-slate-600 truncate max-w-[150px]">
                          {file.mimeType.includes('pdf') ? 'Document.pdf' : 'Image'}
                        </span>
                      </div>
                      <button 
                        onClick={() => removeFile(file.id, false)}
                        className="text-slate-400 hover:text-red-500 p-1"
                      >
                        <X size={14} />
                      </button>
                   </div>
                 ))}
               </div>
             )}
          </div>
        </div>
      )}

      {/* Generate Action */}
      <div className="flex justify-end pt-2">
        <button
          onClick={handleGenerateClick}
          disabled={isGenerateDisabled()}
          className={`flex items-center gap-2 px-8 py-3 rounded-xl font-semibold text-white transition-all shadow-md text-lg
            ${isGenerateDisabled()
              ? 'bg-slate-300 cursor-not-allowed text-slate-500'
              : 'bg-gradient-to-r from-indigo-600 to-violet-600 hover:shadow-xl hover:scale-[1.02] active:scale-[0.98]'
            }`}
        >
          {isGenerating ? (
            <>
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              Processing...
            </>
          ) : (
            <>
              Generate Study Material
            </>
          )}
        </button>
      </div>
    </div>
  );
};

export default InputSection;

import React, { useState } from 'react';
import { Brain, FileText, Layers, AlertCircle, Sparkles, MonitorPlay, ArrowRight } from 'lucide-react';
import { GeneratedContent, UploadedFile, ViewMode } from './types';
import { generateStudyMaterial } from './services/gemini';
import InputSection from './components/InputSection';
import NotesView from './components/NotesView';
import FlashcardDeck from './components/FlashcardDeck';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>(ViewMode.INPUT);
  const [generatedContent, setGeneratedContent] = useState<GeneratedContent | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async (text: string, files: UploadedFile[]) => {
    setIsGenerating(true);
    setError(null);
    try {
      const result = await generateStudyMaterial(text, files);
      setGeneratedContent(result);
      setViewMode(ViewMode.NOTES); // Switch to notes view by default on success
    } catch (err) {
      setError("Failed to generate study materials. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
